  return (
    <div className="dashboard-container">
      <WatchList />
      <div className="content">
        {/* Your Routes for Summary, Orders, etc. */}
      </div>

      {/* Logic to show popup based on context state */}
      {isBuyWindowOpen && <BuyActionWindow mode="BUY" />}
    </div>
  );
};
